<p class="wp-block-paragraph">If you are considering studying in Turkey, this information may be useful for you. At RoadToStudy, we are here to guide you in your study life!</p>', '$.wp_published_at', '2026-04-04T11:00:00Z', '$.wp_modified_at', '2026-03-16T19:50:41Z', '$.featured_image', json('{"provider":"external","src":"/wp-content/uploads/2026/01/a-guide-to-local-media-and-news-sources.webp","alt":"A Guide to Local Media and News Sources in Turkey","title":"a-guide-to-local-media-and-news-sources"}')) WHERE "collection" = 'posts' AND "id" = ( SELECT "live_revision_id" FROM "ec_posts" WHERE "deleted_at" IS NULL AND "status" = 'published' AND "locale" = 'en' AND "slug" = 'a-guide-to-local-media-and-news-sources' );
